sql:
SELECT pin_name
FROM pins
WHERE pin_id = 1;

SELECT COUNT(*) AS pin_type_count, type_name
FROM pin_types
GROUP BY type_name;

SELECT pin_type, AVG(diameter) AS avg_diameter, COUNT(*) AS pin_count
FROM pins
GROUP BY pin_type;

SELECT COUNT(DISTINCT p.pin_id) AS modified_pin_count
FROM pins p
INNER JOIN pin_versions pv ON p.pin_id = pv.pin_id;

SELECT result
FROM tests
WHERE pin_id = 1 AND test_type = 'performance' AND result BETWEEN 0 AND 1;

